// Runs first: cache all known LinkedIn URLs to deduplicate Apify results
const rows = $input.all();
const existingUrls = rows
  .map(r => {
    const url = r.json.linkedin_url || r.json.LinkedIn_URL || '';
    return url.toLowerCase().replace(/\?.*$/, '').trim();
  })
  .filter(url => url.includes('linkedin.com'));

$getWorkflowStaticData('global').existingUrls = existingUrls;

return [{ json: { stored_count: existingUrls.length } }];

// ICP scoring criteria from CLAUDE.md
const existingUrls = new Set($getWorkflowStaticData('global').existingUrls || []);

// Apify sync endpoint returns an array — unwrap if needed
const rawInput = $input.all();
let profiles;
if (rawInput.length === 1 && Array.isArray(rawInput[0].json)) {
  profiles = rawInput[0].json.map(p => ({ json: p }));
} else {
  profiles = rawInput;
}

const scored = profiles.map(item => {
  const d = item.json;

  // Normalise fields (Apify actor output varies by actor version)
  const name = [d.name, d.fullName, `${d.firstName || ''} ${d.lastName || ''}`]
    .map(v => (v || '').trim()).find(v => v.length > 1) || 'Unknown';
  const company = (d.company || d.currentCompany || d.companyName || 'Unknown').trim();
  const rawUrl = d.url || d.profileUrl || d.linkedinUrl || d.linkedInUrl || '';
  const linkedin_url = rawUrl.toLowerCase().replace(/\?.*$/, '').trim();
  const industry = (d.industry || d.companyIndustry || '').toLowerCase();
  const location = (d.location || d.city || d.geoLocation || '').toLowerCase();
  const stage = (d.fundingStage || d.stage || d.fundingRound || '').toLowerCase();
  const headline = (d.headline || d.title || d.occupation || '').toLowerCase();
  const employeeCount = parseInt(d.employeeCount || d.teamSize || d.companySize || 0, 10);

  // Skip if no URL or already in sheet
  if (!linkedin_url || existingUrls.has(linkedin_url)) return null;

  // ── ICP Scoring (from CLAUDE.md) ─────────────────────────
  let score = 0;

  // +30  Recently funded (last 6 months)
  const fundedStr = d.fundedDate || d.lastFundingDate || d.fundingDate || '';
  if (fundedStr) {
    const funded = new Date(fundedStr);
    if (!isNaN(funded.getTime())) {
      const monthsAgo = (Date.now() - funded.getTime()) / (1000 * 60 * 60 * 24 * 30);
      if (monthsAgo <= 6) score += 30;
    }
  }

  // +20  Seed / Pre-Seed stage
  if (['seed', 'pre-seed', 'pre seed', 'bootstrapped', 'angel']
    .some(s => stage.includes(s) || headline.includes(s))) score += 20;

  // +15  B2B SaaS or FinTech
  if (['saas', 'fintech', 'b2b', 'edtech', 'healthtech', 'software', 'financial technology']
    .some(k => industry.includes(k))) score += 15;

  // +10  Indian metro city
  if (['bangalore', 'bengaluru', 'hyderabad', 'mumbai', 'delhi', 'gurugram',
       'gurgaon', 'noida', 'pune', 'chennai'].some(c => location.includes(c))) score += 10;

  // +10  Team size 5–50
  if (employeeCount >= 5 && employeeCount <= 50) score += 10;

  // +15  No CFO / finance head on LinkedIn
  if (!headline.includes('cfo') && !headline.includes('chief financial') &&
      !headline.includes('finance head')) score += 15;

  return {
    json: {
      name,
      company,
      linkedin_url,
      industry,
      location,
      stage: stage || 'seed',
      amount_raised: d.fundingAmount || d.totalFunding || d.lastFundingAmount || '',
      icp_score: score,
      priority: score >= 60 ? 'high' : score >= 40 ? 'medium' : 'low',
      scraped_date: new Date().toISOString().split('T')[0]
    }
  };
}).filter(Boolean);

// Return sentinel if nothing passed — Filter node will drop it cleanly
if (scored.length === 0) {
  return [{ json: { icp_score: 0, _sentinel: true } }];
}
return scored;

const lead = $json;

const systemPrompt = `You are an outreach assistant for Compyte (compyte.in) — an AI CFO platform built for Indian startups.

Generate 3 personalised LinkedIn outreach messages. Return ONLY valid JSON with exactly these 3 keys: connection_request, dm1, dm2.

Rules:
• connection_request — max 300 chars. Mention company name + stage or raise amount. Sound like a 23yo founder who built something cool, NOT a sales rep. Never start with "Hi I'm from Compyte".
• dm1 — max 60 words. Pitch Compyte as their financial OS. Use ONE stage-specific pain point:
  - Pre-Seed/Bootstrapped → "tracking burn in spreadsheets"
  - Seed → "manually pulling MRR numbers for investor updates"
  - Series A → "paying a CA ₹15L/year for GST compliance"
  End message with: compyte.in
• dm2 — max 60 words. 3-day follow-up, completely different angle. Focus on compliance (GSTR-3B, TDS deadlines) OR runway visibility. Zero repetition from dm1.

Never sound templated. Vary sentence structure. Be human.`;

const userMessage = `Lead:
Name: ${lead.name}
Company: ${lead.company}
Stage: ${lead.stage || 'Seed'}
Industry: ${lead.industry || 'SaaS'}
Location: ${lead.location || 'India'}
Amount Raised: ${lead.amount_raised || 'Not disclosed'}
ICP Score: ${lead.icp_score}/100 (${lead.priority} priority)`;

return {
  json: {
    ...lead,
    _claude_body: JSON.stringify({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 800,
      system: systemPrompt,
      messages: [{ role: 'user', content: userMessage }]
    })
  }
};

const claudeResp = $json;
// Retrieve original lead data from the node that still has it
const lead = $('Code — Build Claude Request').item.json;

// Extract text from Anthropic response format
const rawText = claudeResp.content?.[0]?.text || '';

// Parse JSON block from Claude's response
let msgs = { connection_request: '', dm1: '', dm2: '' };
try {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) msgs = JSON.parse(match[0]);
} catch (_) {
  // Graceful fallback — use raw text split into thirds
  msgs.connection_request = rawText.slice(0, 299);
  msgs.dm1 = rawText.slice(299, 599);
  msgs.dm2 = rawText.slice(599, 899);
}

return {
  json: {
    // Lead fields
    name: lead.name,
    company: lead.company,
    stage: lead.stage,
    industry: lead.industry,
    location: lead.location,
    linkedin_url: lead.linkedin_url,
    amount_raised: lead.amount_raised,
    icp_score: lead.icp_score,
    priority: lead.priority,
    scraped_date: lead.scraped_date,
    // Generated messages
    connection_request: (msgs.connection_request || '').slice(0, 299),
    dm1: msgs.dm1 || '',
    dm2: msgs.dm2 || '',
    // Tracker fields (initial state — matches tracker.json schema)
    status: 'new',
    platform: 'linkedin',
    connection_sent_date: '',
    connection_accepted: false,
    dm1_sent_date: '',
    dm1_replied: false,
    dm2_sent_date: '',
    converted: false,
    notes: `ICP: ${lead.priority} (${lead.icp_score}pts)`
  }
};

// LinkedIn safety: random delay 45–120 seconds between actions
const waitSeconds = Math.floor(Math.random() * 76) + 45;
return { json: { ...($input.item.json), _wait_seconds: waitSeconds } };
